const LOGO_DATA = "data:image/png;base64,";

interface LogoProps {
  size?: number;
  className?: string;
}

/**
 * Logo component — renders the original logo.png as an
 * embedded base64 data URI so it works without any external
 * file dependencies.
 */
export function Logo({ size = 32, className = "" }: LogoProps) {
  return (
    <img
      src={LOGO_DATA}
      width={size}
      height={size}
      className={className}
      alt="Check It Out"
      aria-hidden="true"
    />
  );
}
